var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"NOMAD_BORDER_A_KID","text":{"KOREA":"와, 진짜로 다시 움직인다.","JPN":"わぁ、本当にまた動いてる。","ENG":"Whoa! It's really moving again.","TWN":"哇，又動起來咧！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NOMAD_BORDER_C_KID","text":{"KOREA":"그 배에서 가져 온 부품이 효과가 있었나 봐!","JPN":"あの船から持ってきた部品が役に立ったんだね！","ENG":"That part from the ship must have worked!","TWN":"看來從那艘船上拿下來的零件有用欸！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NOMAD_BORDER_B_KID","text":{"KOREA":"신기하다……. 가까이서 봐도 진짜 말 같아.","JPN":"すごい……近くで見ても本当の馬みたい。","ENG":"Wow... It even looks like a real horse up close.","TWN":"好神奇喔……近看也很像真的馬。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그럼 약속한 대로 당신은 오늘부터 국경수비대의 일원이야.","JPN":"それじゃあ約束どおり、今日からあなたは国境守備隊の一員よ。","ENG":"Then, just as promised, you are from now an official member of the Border Guards.","TWN":"那麼按照約定，從今天開始，你就是國境護衛隊的一員。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"확정짓기엔 아직 일러.","JPN":"確定するにはまだ早い。","ENG":"Well, not just yet.","TWN":"現在還言之過早。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"새로 장착한 동력원의 출력이 너무 강해. 부하를 견디지 못하고 폭발할 수도 있어.","JPN":"新しく装着した動力源の出力が強すぎる。負荷に耐えきれず、爆発するかもしれない。","ENG":"The new power generator is too strong. If Hermit can't withstand the load, he could explode.","TWN":"新裝上的動能輸出太強，恐怕會無法承載而發生爆炸。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"문제가 생길 것 같으면 미리 신호를 보내라, 허밋.","JPN":"問題が起こりそうなら前もって合図してくれ、ハーミット。","ENG":"Let me know if anything seems off, Hermit.","TWN":"赫米特，覺得有問題的話，就提前發訊號吧。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HORSE_BORDER_NULL_NAMED","text":{"KOREA":"……!","JPN":"……！","ENG":"...!","TWN":"……！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NOMAD_BORDER_A_KID","text":{"KOREA":"앗, 방금 연기가 새어 나왔어!","JPN":"あっ、今煙が出てた！","ENG":"Huh?! I saw smoke come out of him!","TWN":"呃，剛才在冒煙欸！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NOMAD_BORDER_B_KID","text":{"KOREA":"폭발하려나 봐!","JPN":"爆発するかも！","ENG":"I think he's gonna blow!","TWN":"快要爆炸啦！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NOMAD_BORDER_C_KID","text":{"KOREA":"도망쳐!","JPN":"逃げて！","ENG":"RUN!","TWN":"快逃！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HORSE_BORDER_NULL_NAMED","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"음, 기분은 괜찮아 보이는군.","JPN":"うむ、機嫌はよさそうだな。","ENG":"Hmm, I guess he's feeling fine.","TWN":"嗯，看起來心情不錯。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"녀석을 고칠만한 장소가 있어서 다행이야.","JPN":"こいつを直せる場所があって本当によかった。","ENG":"I'm glad there's a place to fix him.","TWN":"還好有個地方可以修這小子。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"외성에 남아 있던 전쟁 이전의 설비실이야. 한때 셔우드는 병기고 역할도 했으니까.","JPN":"外郭に残っていた戦争の前の設備室。かつてシャーウッドは兵器庫の役割もしていたからね。","ENG":"Sherwood used to be an armory. This is one of the pre-war facilities remaining in the outer castle.","TWN":"是戰爭前留在外城的設備室，因為休烏特曾經是存放武器的地方。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그런데, 그 병기마의 원래 이름이 허밋이었어?","JPN":"ところで、その兵器馬の名前はハーミットだったの？","ENG":"By the way, was \\"Hermit\\" always his name?","TWN":"不過那戰馬原本是叫赫米特嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"적당히 떠오르는 대로 부른 이름이다. 더 괜찮은 이름이 있다면 추천해 줘도 좋아.","JPN":"適当に思い浮かぶままに呼んでいた名前だ。もっといい名前があれば言ってみてくれ。","ENG":"I just called him the first thing that came to mind. If you have a better name, I'm open to suggestions.","TWN":"這是我隨口取的，如果有更好的名字，可以推薦給我。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"로시난테?","JPN":"ロシナンテ？","ENG":"Rocinante?","TWN":"羅西南特？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};